import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void evenLength_floorAverage() {
        // sorted: 1,1,2,3,4,5,6,9 => (3+4)/2 = 3
        assertEquals(3, new Solution().median(new int[]{3, 1, 4, 1, 5, 9, 2, 6}));
    }

    @Test
    void oddLength_exactMiddle() {
        // sorted: 2,3,4,7,10 => middle = 4
        assertEquals(4, new Solution().median(new int[]{7, 2, 10, 4, 3}));
    }

    @Test
    void evenLength_two_elements() {
        // (1+5)/2 = 3
        assertEquals(3, new Solution().median(new int[]{5, 1}));
    }

    @Test
    void singleElement() {
        assertEquals(42, new Solution().median(new int[]{42}));
    }

    @Test
    void allDuplicates_odd() {
        assertEquals(7, new Solution().median(new int[]{7, 7, 7}));
    }

    @Test
    void allDuplicates_even() {
        // (7+7)/2 = 7
        assertEquals(7, new Solution().median(new int[]{7, 7, 7, 7}));
    }

    @Test
    void alreadySorted() {
        // sorted: 1,2,3,4,5 => middle = 3
        assertEquals(3, new Solution().median(new int[]{1, 2, 3, 4, 5}));
    }
}
